messages.content:
Para armazenar secrets no OCI Vault e referenciar em instâncias:

1. **Crie o Vault e Key (pré-requisitos)**:
```hcl
resource "oci_kms_vault" "secrets_vault" {
  compartment_id = var.compartment_ocid
  display_name   = "secrets-vault"
  vault_type     = "DEFAULT"
}

resource "oci_kms_key" "encryption_key" {
  compartment_id      = var.compartment_ocid
  display_name        = "secret-encryption-key"
  management_endpoint = oci_kms_vault.secrets_vault.management_endpoint
  key_shape {
    algorithm = "AES"
    length    = 32
  }
}
```

2. **Crie o Secret**:
```hcl
resource "oci_vault_secret" "db_password" {
  compartment_id = var.compartment_ocid
  display_name   = "database-password"
  vault_id       = oci_kms_vault.secrets_vault.id
  key_id         = oci_kms_key.encryption_key.id

  secret_content {
    content_type = "BASE64"
    content      = base64encode("MyS3cur3P@ssw0rd!")
  }
}
```

3. **Referencie o secret em cloud-init**:
```hcl
resource "oci_core_instance" "app_server" {
  compartment_id = var.compartment_ocid
  display_name   = "app-server"
  shape          = "VM.Standard.E4.Flex"
  shape_config {
    ocpus = 2
    memory_in_gbs = 16
  }

  source_details {
    source_type = "image"
    source_id   = var.image_ocid
  }

  metadata = {
    user_data = base64encode(<<-EOF
#!/bin/bash
# O secret é acessado via OCI CLI ou SDK
export DB_PASSWORD_SECRET_ID="${oci_vault_secret.db_password.id}"
oci vault secret get-base64 --secret-id $DB_PASSWORD_SECRET_ID --query \"data.secret-content.content\" --raw-output | base64 -d > /etc/app/db_password
chmod 600 /etc/app/db_password
EOF
  )
  }
}
```

4. **Policies para acesso ao secret**:
```hcl
resource "oci_identity_dynamic_group" "app_dg" {
  compartment_id = var.tenancy_ocid
  name           = "app-server-dg"
  description    = "App servers that need secret access"
  matching_rule  = "ALL {instance.compartment.id = '${var.compartment_ocid}'}"
}

resource "oci_identity_policy" "secret_access_policy" {
  compartment_id = var.compartment_ocid
  name           = "secret-access-policy"
  statements = [
    "Allow dynamic-group ${oci_identity_dynamic_group.app_dg.name} to read secret-family in compartment ${var.compartment_name}",
    "Allow dynamic-group ${oci_identity_dynamic_group.app_dg.name} to use keys in compartment ${var.compartment_name}",
  ]
}
```

5. **Melhor prática**: Nunca hardcode secrets no Terraform. Use variáveis sensíveis:
```hcl
variable "db_password" {
  type      = string
  sensitive = true
}
```

Ref: https://docs.oracle.com/en-us/iaas/Content/KeyManagement/Tasks/managingsecrets.htm

Para criar políticas de segurança que previnem recursos públicos no OCI:

1. **Policy de IAM para restringir buckets públicos**:
```hcl
resource "oci_identity_policy" "no_public_resources" {
  compartment_id = var.tenancy_ocid
  name           = "no-public-resources-policy"
  description    = "Prevents creation of public-facing resources"
  statements = [
    # Bloqueia buckets públicos
    "Allow group developers to manage objects in compartment ${var.compartment_name} where ALL {request.permission = 'OBJECT_CREATE', request.permission = 'OBJECT_INSPECT'}",
    "Deny any-user to manage object-family in compartment ${var.compartment_name} where ALL {request.permission = 'OBJECT_CREATE', any {target.bucket.name = 'public-*'}}",
  ]
}
```

2. **Cloud Guard para detecção automática**:
```hcl
resource "oci_cloud_guard_target" "security_target" {
  compartment_id     = var.compartment_ocid
  display_name       = "security-compliance-target"
  target_resource_id = var.compartment_ocid
  target_resource_details {
    compartment {
      compartment_id = var.compartment_ocid
    }
  }
}
```

3. **Security Lists sem acesso público desnecessário**:
```hcl
resource "oci_core_security_list" "private_sl" {
  compartment_id = var.compartment_ocid
  vcn_id         = oci_core_vcn.main.id
  display_name   = "private-security-list"

  # Sem ingress rules de 0.0.0.0/0
  ingress_security_rules {
    protocol  = "6"
    source    = "10.0.0.0/16"  # Apenas VCN internal
    stateless = false
    tcp_options {
      max = 443
      min = 443
    }
  }

  # Egress controlado
  egress_security_rules {
    protocol    = "6"
    destination = "0.0.0.0/0"
    stateless   = false
    tcp_options {
      max = 443
      min = 443
    }
  }
}
```

4. **Network Security Groups com escopo mínimo**:
```hcl
resource "oci_core_network_security_group" "app_nsg" {
  compartment_id = var.compartment_ocid
  vcn_id         = oci_core_vcn.main.id
  display_name   = "app-nsg"
}

resource "oci_core_network_security_group_security_rule" "app_rule" {
  network_security_group_id = oci_core_network_security_group.app_nsg.id
  direction                 = "INGRESS"
  protocol                  = "6"
  source                    = "10.0.1.0/24"  # Apenas subnet do LB
  source_type               = "CIDR_BLOCK"
  tcp_options {
    destination_port_range {
      max = 8080
      min = 8080
    }
  }
}
```

5. **Use Terraform Sentinel ou OPA para governance**:
```sentinel
# policy.sentinel - Impede security lists com 0.0.0.0/0
import "tfplan/v2" as tfplan

public_ingress = tfplan.find_resources("oci_core_security_list")

rule "no_public_ingress" {
  description = "Security lists must not allow ingress from 0.0.0.0/0"
  enforce = true

  for public_ingress as address, resource {
    for resource.applied.ingress_security_rules as rule {
      rule.source is "0.0.0.0/0" implies false
    }
  }
}
```

6. **Integre com Resource Manager**:
```hcl
resource "oci_resource_manager_stack" "security_stack" {
  compartment_id = var.compartment_ocid
  display_name   = "security-governance-stack"
  config_source {
    config_source_type = "ZIP_UPLOAD"
  }
  terraform_version = "1.5.0"
}
```

Ref: https://docs.oracle.com/en-us/iaas/Content/Identity/Reference/iampolicyreference.htm
